# Simple in-memory rate limiter
_rate_limit_store: dict = {}


def _cleanup_rate_limit_store():
    """Remove expired entries from rate limit store."""
    now = time.time()
    expired = [k for k, v in _rate_limit_store.items() if now - v['window_start'] > RATE_LIMIT_WINDOW]
    for k in expired:
        del _rate_limit_store[k]


def check_rate_limit(client_id: str) -> bool:
    """Check if client has exceeded rate limit. Returns True if allowed."""
    _cleanup_rate_limit_store()
    now = time.time()

    if client_id not in _rate_limit_store:
        _rate_limit_store[client_id] = {'window_start': now, 'count': 1}
        return True

    entry = _rate_limit_store[client_id]
    if now - entry['window_start'] > RATE_LIMIT_WINDOW:
        _rate_limit_store[client_id] = {'window_start': now, 'count': 1}
        return True

    if entry['count'] >= RATE_LIMIT_MAX_REQUESTS:
        return False

    entry['count'] += 1
    return True


def require_api_key(f):
    """Decorator to enforce API key authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        if not API_KEYS:
            logger.error("No API keys configured. Denying all requests.")
            return jsonify({'error': 'Service not configured'}), 503

        api_key = request.headers.get('X-API-Key', '')
        if not api_key:
            logger.info("Request missing API key from %s", request.remote_addr)
            return jsonify({'error': 'Authentication required'}), 401

        # Constant-time comparison to prevent timing attacks
        key_valid = False
        for valid_key in API_KEYS:
            if hmac_compare(api_key, valid_key):
                key_valid = True
                break

        if not key_valid:
            logger.warning("Invalid API key attempt from %s", request.remote_addr)
            return jsonify({'error': 'Invalid API key'}), 403

        # Rate limiting per API key
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()[:16]
        if not check_rate_limit(key_hash):
            logger.warning("Rate limit exceeded for client from %s", request.remote_addr)
            return jsonify({'error': 'Rate limit exceeded'}), 429

        return f(*args, **kwargs)
    return decorated


def hmac_compare(a: str, b: str) -> bool:
    """Constant-time string comparison to prevent timing attacks."""
    import hmac
    return hmac.compare_digest(a.encode('utf-8'), b.encode('utf-8'))


class ImageClassifier:
    """Secure image classifier with adversarial defense mechanisms."""

    def __init__(self):
        self.device = torch.device('cpu')  # Use CPU for predictable behavior; GPU if needed
        self.model: Optional[torch.nn.Module] = None
