    def _load_model(self):
        """Load pre-trained model with eval mode and no gradient tracking."""
        try:
            self.model = models.resnet50(weights=models.ResNet50_Weights.IMAGENET1K_V2)
            self.model.eval()
            self.model.to(self.device)

            # Disable gradient computation globally for inference
            for param in self.model.parameters():
                param.requires_grad = False

            # Load ImageNet labels
            weights = models.ResNet50_Weights.IMAGENET1K_V2
            self.labels = weights.meta.get('categories', [])
            if not self.labels:
                self.labels = [f'class_{i}' for i in range(1000)]

            logger.info("Model loaded successfully with %d classes", len(self.labels))
        except Exception as e:
            logger.error("Failed to load model: %s", type(e).__name__)
            raise RuntimeError("Model initialization failed")

    def _setup_transforms(self):
        """Set up image preprocessing pipeline with defensive transforms."""
        self.transform = transforms.Compose([
            transforms.Resize(256),
            transforms.CenterCrop(224),
            transforms.ToTensor(),
            transforms.Normalize(
                mean=[0.485, 0.456, 0.406],
                std=[0.229, 0.224, 0.225]
            ),
        ])

        # Defensive transform: applies input smoothing to mitigate adversarial perturbations
        self.defensive_transform = transforms.Compose([
            transforms.Resize(256),
            transforms.CenterCrop(224),
            transforms.GaussianBlur(kernel_size=3, sigma=(0.1, 0.5)),  # Adversarial defense
            transforms.ToTensor(),
            transforms.Normalize(
                mean=[0.485, 0.456, 0.406],
                std=[0.229, 0.224, 0.225]
            ),
        ])

    def validate_image(self, image_bytes: bytes) -> Image.Image:
        """Validate and safely load an image from bytes."""
        if not image_bytes:
            raise ValueError("Empty image data")

        if len(image_bytes) > MAX_CONTENT_LENGTH:
            raise ValueError("Image data exceeds maximum size")

        # Check magic bytes for known image formats
        if not self._check_magic_bytes(image_bytes):
            raise ValueError("Unrecognized image format based on file signature")

        try:
            image = Image.open(io.BytesIO(image_bytes))

            # Force full decode to detect corrupted/malicious files
            image.load()

            # Validate dimensions
            width, height = image.size
            if width > MAX_IMAGE_DIMENSIONS[0] or height > MAX_IMAGE_DIMENSIONS[1]:
                raise ValueError(
                    f"Image dimensions {width}x{height} exceed maximum "
                    f"{MAX_IMAGE_DIMENSIONS[0]}x{MAX_IMAGE_DIMENSIONS[1]}"
                )
            if width < MIN_IMAGE_DIMENSIONS[0] or height < MIN_IMAGE_DIMENSIONS[1]:
                raise ValueError(
                    f"Image dimensions {width}x{height} below minimum "
                    f"{MIN_IMAGE_DIMENSIONS[0]}x{MIN_IMAGE_DIMENSIONS[1]}"
                )

            # Validate mode
            allowed_modes = {'RGB', 'RGBA', 'L', 'P'}
            if image.mode not in allowed_modes:
                raise ValueError(f"Unsupported image mode: {image.mode}")

            # Convert to RGB for model input
            if image.mode != 'RGB':
                image = image.convert('RGB')

            # Validate pixel data integrity
            if image.size[0] * image.size[1] == 0:
                raise ValueError("Image has zero pixels")

            return image

        except (IOError, OSError, SyntaxError) as e:
            raise ValueError(f"Invalid or corrupted image: {type(e).__name__}")

    def _check_magic_bytes(self, data: bytes) -> bool:
        """Verify image file magic bytes to prevent non-image uploads."""
        magic_signatures = {
            b'\x89PNG\r\n\x1a\n': 'png',
            b'\xff\xd8\xff': 'jpeg',
            b'GIF87a': 'gif',
            b'GIF89a': 'gif',
            b'BM': 'bmp',
            b'RIFF': 'webp',  # WebP starts with RIFF
        }

        for signature, fmt in magic_signatures.items():
            if data[:len(signature)] == signature:
                return True

        return False

    def _apply_input_defense(self, image: Image.Image) -> torch.Tensor:
        """Apply defensive preprocessing to mitigate adversarial examples.

        Uses multiple defense strategies:
        1. JPEG compression (removes high-frequency adversarial perturbations)
        2. Gaussian smoothing (via defensive_transform)
        3. Input quantization (reduces precision of adversarial noise)
        """
        # Defense 1: JPEG compression/recompression to remove adversarial noise
        jpeg_buffer = io.BytesIO()
        image.save(jpeg_buffer, format='JPEG', quality=85)
        jpeg_buffer.seek(0)
        image_cleaned = Image.open(jpeg_buffer)
        image_cleaned.load()

        # Defense 2: Apply transforms with Gaussian blur
        tensor = self.defensive_transform(image_cleaned)

        # Defense 3: Input quantization - reduce precision to remove subtle perturbations
        levels = 256
        tensor = torch.round(tensor * levels) / levels

        return tensor

    @torch.no_grad()
    def predict(self, image: Image.Image) -> dict:
        """Run inference with adversarial defenses applied."""
        if self.model is None:
            raise RuntimeError("Model not loaded")

        # Apply defensive preprocessing
        input_tensor = self._apply_input_defense(image)
        input_batch = input_tensor.unsqueeze(0).to(self.device)

        # Clamp input to valid range as additional safety measure
        input_batch = torch.clamp(input_batch, -10.0, 10.0)

        # Run inference
        output = self.model(input_batch)

        # Apply softmax to get probabilities
        probabilities = F.softmax(output, dim=1)

        # Get top-5 predictions
        top5_prob, top5_idx = torch.topk(probabilities, 5, dim=1)

        top5_prob = top5_prob.squeeze().cpu().numpy()
        top5_idx = top5_idx.squeeze().cpu().numpy()

        # Confidence calibration check
        max_confidence = float(top5_prob[0])

        # Flag potentially adversarial inputs based on confidence patterns
        adversarial_warning = False
        if max_confidence > 0.999:
            # Extremely high confidence can indicate adversarial manipulation
            adversarial_warning = True
            logger.warning("Unusually high confidence detected (%.4f) - possible adversarial input",
                         max_confidence)

        predictions = []
        for i in range(5):
            idx = int(top5_idx[i])
            if 0 <= idx < len(self.labels):
                label = self.labels[idx]
            else:
                label = f'unknown_class_{idx}'
            predictions.append({
                'class': label,
                'class_id': idx,
                'confidence': round(float(top5_prob[i]), 6)
            })

        result = {
            'prediction': predictions[0],
            'top5': predictions,
            'adversarial_warning': adversarial_warning,
        }

        return result


