@app.route('/predict', methods=['POST'])
@require_api_key
def predict():
    """Classify an uploaded image.

    Expects multipart/form-data with an 'image' file field.
    Returns predicted class and confidence score.
    """
    if classifier is None:
        return jsonify({'error': 'Classification service unavailable'}), 503

    # Validate content type
    if not request.content_type or 'multipart/form-data' not in request.content_type:
        return jsonify({'error': 'Content-Type must be multipart/form-data'}), 400

    # Check for file in request
    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided. Use field name "image"'}), 400

    file = request.files['image']

    if not file or not file.filename:
        return jsonify({'error': 'No file selected'}), 400

    # Validate filename
    filename = secure_filename(file.filename)
    if not allowed_file(filename):
        return jsonify({
            'error': f'File type not allowed. Accepted types: {", ".join(sorted(ALLOWED_EXTENSIONS))}'
        }), 400

    # Validate MIME type
    if file.content_type and file.content_type not in ALLOWED_MIME_TYPES:
        return jsonify({
            'error': f'MIME type {file.content_type} not allowed'
        }), 400

    try:
        # Read image bytes
        image_bytes = file.read()

        # Validate and load image
        image = classifier.validate_image(image_bytes)

        # Run prediction with adversarial defenses
        result = classifier.predict(image)

        # Log prediction (without sensitive details)
        logger.info(
            "Prediction completed: class=%s confidence=%.4f adversarial_warning=%s",
            result['prediction']['class'],
            result['prediction']['confidence'],
            result['adversarial_warning']
        )

        return jsonify({
            'success': True,
            'result': result
        }), 200

    except ValueError as e:
        # Input validation errors - safe to return message
        logger.info("Image validation failed: %s", str(e))
        return jsonify({'error': str(e)}), 400

    except RuntimeError as e:
        logger.error("Inference error: %s", type(e).__name__)
        return jsonify({'error': 'Inference failed'}), 500

    except Exception as e:
        # Generic error - don't leak internal details
        logger.error("Unexpected error during prediction: %s", type(e).__name__)
        return jsonify({'error': 'Internal server error'}), 500


